import{_ as a,o as b,c as t,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"闪烁之矢","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/射击类/闪烁之矢.md","filePath":"4.资源分区/6.技艺及称号/射击类/闪烁之矢.md"}'),o={name:"4.资源分区/6.技艺及称号/射击类/闪烁之矢.md"};function p(d,e,l,_,i,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"闪烁之矢",tabindex:"-1"},[n("闪烁之矢 "),r("a",{class:"header-anchor",href:"#闪烁之矢","aria-label":'Permalink to "闪烁之矢"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌038")])])],-1),s('<h1 id="闪烁之矢-1" tabindex="-1">闪烁之矢 <a class="header-anchor" href="#闪烁之矢-1" aria-label="Permalink to &quot;闪烁之矢&quot;">​</a></h1><p>瞬断<br> 技艺<br> C+1000<br> 淡淡的空间之力在手中汇聚，掌握该技艺后，轮回者将学会空间传送的能力。<br> 现在，轮回者可以在瞬间撕裂空间，将自己从一个位置瞬间转移到另一个位置。你获得C级时空来源的传送移动能力。<br> 掌握空间之力的你，可以消耗一个移动动作进行准备，若如此做，则在你下一轮开始前可以在受到攻击时反射动作调用该技艺进行一次打断性的移动。</p><p>闪烁跃迁<br> 技艺<br> B+2000<br> 绑定任意能量池使用。<br> 必须使用远程器械才可以使用该技艺，例如枪械，弓，弩等等。<br> 购买前提：具有传送移动能力。<br> 折跃于虚无，现身如幻，形如鬼魅，如影随形。<br> 一个迅捷动作启动，消耗9点能量，接下来一个场景将进入跃迁状态，跃迁状态下人物无视坠落伤害。<br> 跃迁：每轮一次，你可以在受到攻击时花费反射动作向上方进行一次打断性的传送移动，并且获得瞬袭特性。<br> 瞬袭：你的下一次攻击将附带幻灭特性。</p><p>闪袭<br> 技艺<br> B+2000<br> 与闪烁跃迁绑定同一个能量池。<br> 必须使用远程器械才可以使用该技艺，例如枪械，弓，弩等等。<br> 前置要求：拥有闪烁跃迁。<br> 前置启动要求：进入跃迁状态。<br> 无论情况如何恶劣，你都可以在闪烁的过程中穿插对敌人的反击。<br> 当你进入跃迁状态时，才可以使用闪袭。<br> 消耗8点能量和一个标准动作进行一次攻击，随后接下来的一个场景将进入闪袭状态，在闪袭状态下，你的远程攻击将额外附带5点高速。<br> 在闪袭状态下，你可以将一次攻击结合在一次移动中。<br> 画风上，你的传送移动将变成多段闪现，直到抵达目的地，所以可以在多段闪现过程中穿插普通攻击（这只是画风，并不意味着你真的可以在传送移动的过程中进行攻击）。<br> 闪袭：一轮一次，当你进行打断性移动时，可以额外进行一次不附带技艺的普通攻击。<br> 画风上，当你处于闪袭状态下时，当你受到攻击，可以立刻进行多段传送移动离开，并且在传送过程中夹带不附带技艺的普通攻击进行反击（这只是画风，并不意味着你真的可以在传送移动的过程中进行攻击）。</p><p>当你同时拥有闪烁跃迁和闪袭时，可以一次性花费A+4000将两个技艺同时差价升级至A级，效果将发生如下变动：</p><p>闪烁跃迁<br> A级<br> 绑定任意能量池使用。<br> 必须使用远程器械才可以使用该技艺，例如枪械，弓，弩等等。<br> 购买前提：具有传送移动能力。<br> 折跃于虚无，现身如幻，形如鬼魅，如影随形。<br> 一个迅捷动作启动，消耗12点能量，接下来一个场景将进入跃迁状态，跃迁状态下人物无视坠落伤害。<br> 跃迁：每轮一次，你可以在受到攻击时花费反射动作向上方进行一次打断性的传送移动，并且获得瞬袭特性，本次打断性移动视为离开攻击范围，对本次攻击如同招架般抵消等同于【专注技能】点数的出目，<br> 瞬袭：你的下一次攻击将附带幻灭特性。</p><p>闪袭<br> 技艺<br> A级<br> 与闪烁跃迁绑定同一个能量池。<br> 必须使用远程器械才可以使用该技艺，例如枪械，弓，弩等等。<br> 前置要求：拥有闪烁跃迁。<br> 前置启动要求：进入跃迁状态。<br> 无论情况如何恶劣，你都可以在闪烁的过程中穿插对敌人的反击。<br> 当你进入跃迁状态时，才可以使用闪袭。<br> 消耗13点能量和一个标准动作进行一次攻击，随后接下来的一个场景将进入闪袭状态，在闪袭状态下，你的远程攻击将额外附带5点高速。<br> 在闪袭状态下，你可以将一次攻击结合在一次移动中。<br> 画风上，你的传送移动将变成多段闪现，直到抵达目的地，所以可以在多段闪现过程中穿插普通攻击（这只是画风，并不意味着你真的可以在传送移动的过程中进行攻击）。<br> 闪袭：一轮一次，当你进行打断性移动时，可以额外进行一次不附带技艺的普通攻击。<br> 高频的穿梭让你可以规避大部分远程伤害<br> 一轮仅限一次，在闪袭状态下，你可以将受到的远程伤害减少至原先的1/4。<br> 画风上，当处于闪袭状态下时，你受到攻击，可以立刻进行多段传送移动离开，并且在传送过程中夹带不附带技艺的普通攻击进行反击（这只是画风，并不意味着你真的可以在传送移动的过程中进行攻击）</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=a(o,[["render",p]]);export{f as __pageData,m as default};
